def compute_score() -> tuple[str, float]:
    from pptx import Presentation

    try:
        original_ppt = Presentation(original_ppt_path)
        modified_ppt = Presentation(modified_ppt_path)

        if len(original_ppt.slides) < 12 or len(modified_ppt.slides) < 12:
            return "Slide 12 not found in one or both presentations", 0.0

        original_slide = original_ppt.slides[11]
        modified_slide = modified_ppt.slides[11]

        # Extract all text from both slides
        def extract_text_from_slide(slide):
            texts = []
            for shape in slide.shapes:
                if hasattr(shape, 'text'):
                    texts.append(shape.text.strip())
            return texts

        original_texts = extract_text_from_slide(original_slide)
        modified_texts = extract_text_from_slide(modified_slide)

        # Normalize whitespace and compare
        original_normalized = [' '.join(text.split()) for text in original_texts if text]
        modified_normalized = [' '.join(text.split()) for text in modified_texts if text]

        original_normalized.sort()
        modified_normalized.sort()

        if original_normalized == modified_normalized:
            return "Text content on slide 12 remains unchanged", 1.0
        else:
            return f"Text content changed on slide 12. Original: {len(original_normalized)} items, Modified: {len(modified_normalized)} items", 0.0

    except Exception as e:
        return f"Error comparing text content: {str(e)}", 0.5
